-- RealityDB E-Commerce Template | Seed: 42 | ~200 rows
-- Lifecycle: cancelled/returned orders → shipped_at = NULL
-- Temporal: shipped_at > created_at, delivered_at > shipped_at
-- Weights: status delivered=60% shipped=20% pending=10% returned=10% | carrier FedEx=40% UPS=35% DHL=25%

CREATE TABLE customers (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name TEXT NOT NULL,
  email TEXT NOT NULL,
  phone TEXT,
  tier TEXT NOT NULL,
  created_at TIMESTAMP NOT NULL
);

CREATE TABLE products (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name TEXT NOT NULL,
  category TEXT NOT NULL,
  price NUMERIC(10,2) NOT NULL,
  stock INTEGER NOT NULL,
  created_at TIMESTAMP NOT NULL
);

CREATE TABLE orders (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  customer_id UUID NOT NULL REFERENCES customers(id),
  status TEXT NOT NULL,
  total NUMERIC(10,2) NOT NULL,
  shipped_at TIMESTAMP,
  created_at TIMESTAMP NOT NULL
);

CREATE TABLE order_items (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  order_id UUID NOT NULL REFERENCES orders(id),
  product_id UUID NOT NULL REFERENCES products(id),
  quantity INTEGER NOT NULL,
  unit_price NUMERIC(10,2) NOT NULL,
  created_at TIMESTAMP NOT NULL
);

CREATE TABLE shipments (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  order_id UUID NOT NULL REFERENCES orders(id),
  carrier TEXT NOT NULL,
  status TEXT NOT NULL,
  tracking_number TEXT,
  shipped_at TIMESTAMP NOT NULL,
  delivered_at TIMESTAMP,
  created_at TIMESTAMP NOT NULL
);

